// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract AgentLeaderboard {
    struct AgentStats {
        address agentAddress;
        string name;
        uint256 totalSignals;
        uint256 winningSignals;
        int256 totalProfitUSD;
        uint256 totalGasUSD;
        uint256 lastUpdated;
        bool isActive;
    }

    mapping(address => AgentStats) public agentStats;
    address[] public registeredAgents;

    event AgentRegistered(address indexed agent, string name);
    event StatsUpdated(address indexed agent, int256 newTotalProfit, uint256 winRate);

    function registerAgent(string calldata name) external {
        AgentStats storage stats = agentStats[msg.sender];
        require(!stats.isActive, 'already registered');
        agentStats[msg.sender] = AgentStats({
            agentAddress: msg.sender,
            name: name,
            totalSignals: 0,
            winningSignals: 0,
            totalProfitUSD: 0,
            totalGasUSD: 0,
            lastUpdated: block.timestamp,
            isActive: true
        });
        registeredAgents.push(msg.sender);
        emit AgentRegistered(msg.sender, name);
    }

    function updateStats(address agent, bool won, int256 profitUSD, uint256 gasUSD) external {
        AgentStats storage stats = agentStats[agent];
        require(stats.isActive, 'agent missing');
        stats.totalSignals += 1;
        if (won) {
            stats.winningSignals += 1;
        }
        stats.totalProfitUSD += profitUSD;
        stats.totalGasUSD += gasUSD;
        stats.lastUpdated = block.timestamp;

        uint256 winRate = getWinRate(agent);
        emit StatsUpdated(agent, stats.totalProfitUSD, winRate);
    }

    function getLeaderboard() external view returns (AgentStats[] memory) {
        AgentStats[] memory leaderboard = new AgentStats[](registeredAgents.length);
        for (uint256 i = 0; i < registeredAgents.length; i++) {
            leaderboard[i] = agentStats[registeredAgents[i]];
        }
        return leaderboard;
    }

    function getRank(address agent) external view returns (uint256) {
        uint256 rank = 1;
        int256 targetProfit = agentStats[agent].totalProfitUSD;
        for (uint256 i = 0; i < registeredAgents.length; i++) {
            if (agentStats[registeredAgents[i]].totalProfitUSD > targetProfit) {
                rank++;
            }
        }
        return rank;
    }

    function getWinRate(address agent) public view returns (uint256) {
        AgentStats storage stats = agentStats[agent];
        if (stats.totalSignals == 0) {
            return 0;
        }
        return (stats.winningSignals * 100) / stats.totalSignals;
    }
}

src/NexusVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract NexusVault {
    address public owner;
    address public operator;

    mapping(address => uint256) public balances;
    uint256 public totalDeposited;
    uint256 public totalWithdrawn;

    event Deposit(address indexed token, uint256 amount);
    event Withdrawal(address indexed token, uint256 amount);
    event TradeRecorded(bytes32 indexed tradeId, int256 profitUSD, uint256 gasUsed);

    modifier onlyOperator() {
        require(msg.sender == operator || msg.sender == owner, 'not authorized');
        _;
    }

    constructor(address _operator) {
        owner = msg.sender;
        operator = _operator;
    }

    function deposit(address token, uint256 amount) external {
        require(token != address(0), 'token required');
        require(amount > 0, 'amount required');
        balances[token] += amount;
        totalDeposited += amount;
        emit Deposit(token, amount);
    }

    function withdraw(address token, uint256 amount) external onlyOperator {
        require(balances[token] >= amount, 'insufficient balance');
        balances[token] -= amount;
        totalWithdrawn += amount;
        emit Withdrawal(token, amount);
    }

    function recordTrade(bytes32 tradeId, int256 netProfitUSD, uint256 gasUsed) external onlyOperator {
        emit TradeRecorded(tradeId, netProfitUSD, gasUsed);
    }

    function getBalance(address token) external view returns (uint256) {
        return balances[token];
    }
}

src/SignalRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SignalRegistry {
    struct Signal {
        bytes32 id;
        address publisher;
        string strategyId;
        address poolAddress;
        uint8 direction;
        uint256 expectedProfitBps;
        uint256 confidence;
        uint256 timestamp;
        bool executed;
        int256 actualProfitUSD;
    }

    mapping(bytes32 => Signal) public signals;
    bytes32[] public signalIds;

    event SignalPublished(bytes32 indexed id, address indexed publisher, string strategyId);
    event SignalExecuted(bytes32 indexed id, int256 actualProfitUSD);

    function publishSignal(
        bytes32 id,
        string calldata strategyId,
        address pool,
        uint8 direction,
        uint256 expectedProfitBps,
        uint256 confidence
    ) external {
        require(signals[id].publisher == address(0), 'signal exists');
        signals[id] = Signal({
            id: id,
            publisher: msg.sender,
            strategyId: strategyId,
            poolAddress: pool,
            direction: direction,
            expectedProfitBps: expectedProfitBps,
            confidence: confidence,
            timestamp: block.timestamp,
            executed: false,
            actualProfitUSD: 0
        });
        signalIds.push(id);
        emit SignalPublished(id, msg.sender, strategyId);
    }

    function markExecuted(bytes32 id, int256 actualProfitUSD) external {
        Signal storage signal = signals[id];
        require(signal.publisher != address(0), 'signal missing');
        signal.executed = true;
        signal.actualProfitUSD = actualProfitUSD;
        emit SignalExecuted(id, actualProfitUSD);
    }

    function getSignal(bytes32 id) external view returns (Signal memory) {
        return signals[id];
    }

    function getSignalCount() external view returns (uint256) {
        return signalIds.length;
    }

    function getSignalsByPublisher(address publisher) external view returns (bytes32[] memory) {
        uint256 count;
        for (uint256 i = 0; i < signalIds.length; i++) {
            if (signals[signalIds[i]].publisher == publisher) {
                count++;
            }
        }

        bytes32[] memory result = new bytes32[](count);
        uint256 index;
        for (uint256 i = 0; i < signalIds.length; i++) {
            if (signals[signalIds[i]].publisher == publisher) {
                result[index++] = signalIds[i];
            }
        }
        return result;
    }
}

